function b64url(v) {
  return Buffer.from(typeof v === 'string' ? v : JSON.stringify(v))
    .toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
}
function makeJWT(scope) {
  const now = Math.floor(Date.now()/1000);
  const hdr  = { alg:'RS256', typ:'JWT' };
  const pay  = { iss:SA_EMAIL, scope, aud:'https://oauth2.googleapis.com/token', iat:now, exp:now+3600 };
  const msg  = b64url(hdr)+'.'+b64url(pay);
  const sign = crypto.createSign('RSA-SHA256');
  sign.update(msg);
  return msg+'.'+sign.sign(PRIVATE_KEY,'base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
}

// 1. Obtener token
const tokenResp = await $helpers.httpRequest({
  method:'POST', url:'https://oauth2.googleapis.com/token',
  headers:{'Content-Type':'application/x-www-form-urlencoded'},
  body:`grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${makeJWT('https://www.googleapis.com/auth/spreadsheets')}`
});
const token = tokenResp.access_token;

// 2. Leer sheet
const sheetResp = await $helpers.httpRequest({
  url:`https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${SHEET_RANGE}`,
  headers:{'Authorization':`Bearer ${token}`}
});
const rows = sheetResp.values || [];
if (rows.length < 2) return [{ json:{ skip:true, reason:'Sin leads', token, sheetId:SHEET_ID } }];

const headers = rows[0];
const now = Date.now();
const DAY = 86400000;

const leads = [];
for (let i = 1; i < rows.length; i++) {
  const r = rows[i];
  const obj = {};
  headers.forEach((h,idx) => obj[h] = r[idx] || '');
  obj._row = i + 1; // fila en el sheet (1-indexed, con header en fila 1)

  const regDate = new Date(obj['Fecha_Registro']).getTime();
  const daysSince = isNaN(regDate) ? 0 : (now - regDate) / DAY;
  const d1 = (obj['Email_Enviado_D1'] || '').trim().toUpperCase();
  const d3 = (obj['Email_Enviado_D3'] || '').trim().toUpperCase();
  const d7 = (obj['Email_Enviado_D7'] || '').trim().toUpperCase();

  if (d1 !== 'SI') {
    leads.push({ ...obj, _emailDay:1, _row:obj._row, token, sheetId:SHEET_ID });
  } else if (d3 !== 'SI' && daysSince >= 3) {
    leads.push({ ...obj, _emailDay:3, _row:obj._row, token, sheetId:SHEET_ID });
  } else if (d1 === 'SI' && d3 === 'SI' && d7 !== 'SI' && daysSince >= 7) {
    leads.push({ ...obj, _emailDay:7, _row:obj._row, token, sheetId:SHEET_ID });
  }
}

if (!leads.length) return [{ json:{ skip:true, reason:'Sin leads pendientes', token, sheetId:SHEET_ID } }];
return leads.map(l => ({ json: l }));

const lead = $input.first().json;
if (lead.skip || lead._sendError) {
  if (lead._sendError) {
    // Registrar error en col H
    const col = 'H';
    await $helpers.httpRequest({
      method:'PUT',
      url:`https://sheets.googleapis.com/v4/spreadsheets/${lead.sheetId}/values/Contactos!${col}${lead._row}?valueInputOption=RAW`,
      headers:{'Authorization':`Bearer ${lead.token}`,'Content-Type':'application/json'},
      body: JSON.stringify({ values:[[`Error: ${lead._sendError}`]] })
    });
  }
  return [{ json: lead }];
}

const now = new Date().toLocaleString('es-AR', { timeZone:'America/Argentina/Buenos_Aires' });
const dayColMap = { 1:'D', 3:'E', 7:'F' }; // D=D1, E=D3, F=D7
const col = dayColMap[lead._emailDay];

await $helpers.httpRequest({
  method:'PUT',
  url:`https://sheets.googleapis.com/v4/spreadsheets/${lead.sheetId}/values/Contactos!${col}${lead._row}?valueInputOption=RAW`,
  headers:{'Authorization':`Bearer ${lead.token}`,'Content-Type':'application/json'},
  body: JSON.stringify({ values:[[`SI - ${now}`]] })
});

return [{ json: { success:true, email:lead['Email'], day:lead._emailDay, row:lead._row, updatedAt:now } }];
